#define DCREG_OUTPUT2_CONFIG_RESET                                           1:1
#define   DCREG_OUTPUT2_CONFIG_RESET_RESET                                   0x1

/* Force HW copy the shadow register to active register directly.  */
#define DCREG_OUTPUT2_CONFIG_FORCE_FLIP                                      2:2

